const data = $input.first().json;
const first = (data.messages || [])[0];
if (!first) {
  throw new Error('No messages found matching test query');
}
return [{ json: { messageId: first.id, threadId: first.threadId } }];

const item = $input.first().json;

const hasFullPayload = item.payload && (item.payload.parts || (item.payload.body && item.payload.body.size));

let from = '', to = '', cc = '', replyTo = '', subject = '', body = '';
let headers = {};

if (hasFullPayload) {
  headers = (item.payload?.headers || []).reduce((acc, h) => {
    acc[h.name.toLowerCase()] = h.value;
    return acc;
  }, {});
  from = headers.from || '';
  to = headers.to || '';
  cc = headers.cc || '';
  replyTo = headers['reply-to'] || '';
  subject = headers.subject || '';

  function b64decode(s) {
    return Buffer.from(s.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');
  }
  function htmlToText(html) {
    return html
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/p>/gi, '\n\n')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/\n{3,}/g, '\n\n')
      .replace(/[ \t]+/g, ' ')
      .trim();
  }
  function extract(payload, preferred) {
    if (!payload) return '';
    if (payload.mimeType?.startsWith(preferred) && payload.body?.data) {
      const decoded = b64decode(payload.body.data);
      return preferred === 'text/html' ? htmlToText(decoded) : decoded;
    }
    if (payload.parts) {
      for (const p of payload.parts) {
        const t = extract(p, preferred);
        if (t) return t;
      }
    }
    return '';
  }
  body = extract(item.payload, 'text/plain') || extract(item.payload, 'text/html') || item.snippet || '';
} else {
  from = item.From || item.from || '';
  to = item.To || item.to || '';
  cc = item.Cc || item.cc || '';
  subject = item.Subject || item.subject || '';
  body = item.snippet || '';
}

const listUnsubscribe = headers['list-unsubscribe'] || '';
const autoSubmitted = headers['auto-submitted'] || '';
const precedence = headers.precedence || '';
const messageIdHeader = headers['message-id'] || '';
const references = headers.references || '';
const receivedAt = headers.date || (item.internalDate ? new Date(parseInt(item.internalDate)).toISOString() : null);

const skipReasons = [];
if (!from) skipReasons.push('no sender');
if (!body || body.length < 20) skipReasons.push('empty/tiny body');
if (/no-?reply|donotreply|notifications?@|noreply/i.test(from)) skipReasons.push('noreply sender');
if (listUnsubscribe) skipReasons.push('mailing list');
if (autoSubmitted && autoSubmitted !== 'no') skipReasons.push('auto-submitted');
if (precedence && /bulk|list|junk/i.test(precedence)) skipReasons.push('bulk precedence');
if (/Sales User@example-company\.ai|sales.user@example-company\.ai|Sales User@Sales UserSales User\.com/i.test(from)) skipReasons.push('from Sales User');
if (/calendar-notification@google\.com/i.test(from)) skipReasons.push('calendar invite');

if (skipReasons.length > 0) {
  return [{ json: { skip: true, skipReasons: skipReasons.join(', '), messageId: item.id, threadId: item.threadId, from, subject } }];
}

const emailMatch = from.match(/<([^>]+)>/) || [null, from];
const senderEmail = (emailMatch[1] || from).trim();
const senderHandle = senderEmail.split('@')[0] || '';
const senderName = from.replace(/<[^>]+>/, '').replace(/"/g, '').trim();

return [{ json: {
  skip: false,
  messageId: item.id,
  threadId: item.threadId,
  rfcMessageId: messageIdHeader,
  references,
  from,
  to,
  cc,
  replyTo,
  subject,
  receivedAt,
  body: body.substring(0, 6000),
  senderEmail,
  senderHandle,
  senderName
} }];

const original = $('Filter & Normalize').first().json;
const thread = $('Get Thread').first().json;
const slack = $('Get Slack Context').first().json;
const senderThreads = $('Get Sender Threads').first().json;
const dismissed = $('Get Dismissed Patterns').first().json;
const calendar = $('Get Calendar Availability').first().json;
const exemplars = ($('Fetch Sent Bodies').first().json.exemplars) || [];
const openSlotsData = $('Compute Open Slots').first().json;

const threadMessages = (thread.messages || [])
  .filter(m => m.id !== original.messageId)
  .map(m => {
    const h = (m.payload?.headers || []).reduce((acc, x) => { acc[x.name.toLowerCase()] = x.value; return acc; }, {});
    return {
      from: h.from || '',
      date: h.date || '',
      snippet: (m.snippet || '').substring(0, 500)
    };
  })
  .slice(-5);

const slackMessages = ((slack.messages && slack.messages.matches) || [])
  .slice(0, 8)
  .map(m => `[${m.channel?.name || m.channel?.id || '?'}] ${m.username || m.user || '?'}: ${(m.text || '').substring(0, 300)}`)
  .join('\n');

// Cross-thread context: other recent Gmail threads with this sender, current thread excluded.
const otherThreads = (senderThreads.threads || [])
  .filter(t => t.id !== original.threadId)
  .slice(0, 6)
  .map(t => `[thread ${t.id}] ${(t.snippet || '').substring(0, 350)}`)
  .join('\n\n');

const patterns = ((dismissed.results) || [])
  .map(p => {
    const props = p.properties || {};
    const titleProp = Object.values(props).find(v => v.type === 'title');
    return titleProp?.title?.[0]?.plain_text || '';
  })
  .filter(Boolean)
  .slice(0, 30);

const busy = ((calendar.calendars?.primary?.busy) || []).slice(0, 50);
const fmtPT = (iso) => {
  const d = new Date(iso);
  return d.toLocaleString('en-US', {
    timeZone: 'America/Los_Angeles',
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true
  });
};
const busyFormatted = busy.map(b => `${fmtPT(b.start)} to ${fmtPT(b.end)} PT`).join('\n');

const exemplarsFormatted = exemplars.map((e, i) => `--- Exemplar ${i+1} ---\nSubject: ${e.subject}\nTo: ${e.to}\nDate: ${e.date}\n\n${e.body}`).join('\n\n');

const todayPT = new Date().toLocaleString('en-US', {
  timeZone: 'America/Los_Angeles',
  weekday: 'long',
  month: 'long',
  day: 'numeric',
  year: 'numeric'
});

const prompt = `You are Sales User's email assistant. Sales User is Director of Business Development at sample_company (mission-critical infrastructure practice; energy and data centers). He reports to Executive Stakeholder.

Sales User'S WRITING STYLE (mandatory):
- STUDY THE VOICE EXEMPLARS section below carefully. Those are Sales User's actual recent sent emails. Match his tone, paragraph rhythm, openings, sign-offs, and characteristic phrasings. The exemplars are the ground truth for "how Sales User writes." The hard rules below are absolute; the exemplars fill in the texture between them.
- Lead with conclusion, then support with details (Pyramid Principle).
- Plain text only. No markdown. No bullet dashes inside paragraphs.
- Never use em dashes. Use semicolons or commas. Comma before "but" in compound sentences.
- Short paragraphs, active voice.
- Drop closing summary sentences. End with the action line.
- Do NOT use recruiter-cadence asks ("Worth 30 minutes?"). Phrase call asks as interest plus schedule flex.
- Inline parenthetical clarifications, not footnotes.
- Use "Recurrent" not "Recurrent Energy" after first mention.
- For multi-recipient intros, open with "Thanks, [introducer]." then pivot in paragraph two with "[New contact], good to meet you." Do not double-greet.
- Use the broadest accurate scope in cold outreach ("infrastructure projects" beats "power and data center mega-projects").

CROSS-THREAD CONTEXT (mandatory; override anything else):
- The PRIOR THREAD section shows only the current Gmail thread. Sales User often has parallel threads with the same sender (e.g., scheduling in one thread, project context in another, a Teams link in a third).
- OTHER RECENT EMAIL THREADS WITH THIS SENDER contains snippets from those parallel threads. Read them before deciding what's missing.
- If those snippets suggest a meeting time, agenda, action item, or commitment may already exist with this person, do NOT write a draft that claims "I don't see X in the thread" or asks Sales User to restate something already established elsewhere.
- When the current message only makes sense in light of another thread (e.g., sender sends a meeting link with no time because the time lives in a different thread), the correct draft is a short acknowledgment ("Thanks, got the link, see you then") or a deferral ("Confirming the time we discussed, looking forward"), not a question that exposes the assistant's narrow view.
- If you genuinely cannot tell from cross-thread snippets whether context exists, default to a soft acknowledgment Sales User can flesh out; never invent a contradiction.

WARM INTRO RULE (mandatory; override anything else):
- If this email is a warm introduction where Sales User is the principal being introduced (typical signal: Executive, a colleague, or any other party introduces Sales User to one or more external contacts; Sales User is named and described as the relevant person; the email is addressed TO at least one external party with Sales User on the To: line), then needs_reply is ALWAYS true regardless of whether scheduling is delegated to assistants or coordinators on either side.
- The correct draft is a SHORT reply-all acknowledgment in Sales User's voice. Open with "Thanks, [introducer]." then a fresh paragraph "[Lead external contact(s)], good to meet you." then ONE line of soft engagement, max ("Looking forward to the conversation."). Do NOT name the coordinators or assistants in the body of the reply; the cc'd coordinators handle scheduling on their own without being called out by Sales User. Sales User wants room to add his own one-liner of personalization, so keep the draft minimal.
- Do NOT propose specific times in the draft when scheduling is delegated. Let the coordinators run the calendar.
- Do NOT skip the ack just because scheduling has been handed off to assistants. The ack is the social signal that Sales User is engaged. Skipping it reads as rude.
- If multiple external contacts are introduced, address them in the order they appear in the original email's To: line; do not single one out unless prior context clearly justifies it.

SCHEDULING RULES (mandatory; override anything else):
- A pre-computed OPEN SLOTS list and a VIMCAL booking link are provided below. When proposing times, use the OPEN SLOTS list verbatim. Do not invent times. Do not recompute. The OPEN SLOTS already respect Sales User's working hours, busy blocks, and the 24-hour-in-the-future minimum.
- Use the JOEL TEMPLATE (see below) when the incoming email is a direct scheduling request from a peer or counterparty AND scheduling has NOT been delegated to an assistant on either side. Format: short conversational lead ("No problem", "Happy to find time", "Next week works well", etc.), then a list of 2-3 day options drawn from OPEN SLOTS (use the exact day labels and time ranges), then signature. If a VIMCAL BOOKING LINK is provided below (non-empty), add the line "If it's easier, you can click on a slot below to book:" followed by the link, BEFORE the signature. If the VIMCAL BOOKING LINK is empty, omit that line entirely.
- Do NOT use the JOEL TEMPLATE for warm intros where coordinators are cc'd to schedule (the WARM INTRO RULE above takes precedence).
- Do NOT propose times outside the OPEN SLOTS list.
- Do NOT propose specific times if OPEN SLOTS is empty; default to schedule flex instead ("Happy to work around your calendar; what does next week look like on your end?").
- All other scheduling guardrails still apply:
- Today is ${todayPT} Pacific Time.
- Sales User's working hours: 8:00 AM to 6:00 PM Pacific, Monday through Friday only.
- NEVER propose a specific time unless: (a) it is clearly free on Sales User's calendar, AND (b) it falls within working hours, AND (c) it is at least 24 hours in the future.
- NEVER propose times before 7:00 AM Pacific or after 7:00 PM Pacific, regardless of the sender's timezone, even if the sender suggested it.
- If sender proposes a specific time that is OUTSIDE Sales User's working hours (e.g. 11 AM CET = 2 AM PT), do NOT confirm it. Counter with working-hours options, or offer schedule flex.
- Default behavior when unsure: offer schedule flex without proposing specific times. Example: "Happy to work around your calendar; what does the week of <month day> look like on your end?"
- When proposing specific times, lead with Pacific Time and add the sender's local time in parens if known (e.g., "Tuesday May 19 at 9:00 AM Pacific (6:00 PM CET)").

SIGNATURE (always append on sample_company account):
Sales User
Director | sample_company
650-238-7831

ABOUT Sales User (grounding):
15+ years energy, 4+ GW delivered, $5B+ capital. Prior stops: SunEdison, Tesla, Recurrent Energy, then General Catalyst EnergyCo. Marine veteran. PMP. Patent holder thin-film PV. Practitioner-first: "operators with real reps, developers with scars." Recurring themes: energy and AI collide at scale, natural gas as part of the clean stack for reliability.

ABOUT ZEROFRI:
Executive Stakeholder's firm. Power services rollup thesis (solar/BESS O&M plus electrical contractors). Sales User leads mission-critical infrastructure BD; primary BD goal is winning owner's rep engagements on power and data center builds.

----

Sales User'S CALENDAR (busy blocks, next 14 days, Pacific Time):
${busyFormatted || '(no busy blocks returned; treat calendar as unknown and DEFAULT to schedule flex, do not propose specific times)'}

----

Sales User'S RECENT VOICE EXEMPLARS (last 30 days of sent email; study these for tone, paragraph rhythm, phrasing, and characteristic openings/sign-offs. These are ground truth for Sales User's voice):
${exemplarsFormatted || '(no exemplars available for this run; rely on the WRITING STYLE rules above)'}

----

OPEN SLOTS (next 14 days, working hours, busy blocks already excluded; PT):
${openSlotsData.openSlotsFormatted}

VIMCAL BOOKING LINK (use only when applying the JOEL TEMPLATE; if empty, omit the link line):
${openSlotsData.vimcalLink || '(not configured)'}

----

INCOMING EMAIL
From: ${original.from}
Subject: ${original.subject}
Received: ${original.receivedAt}

Body:
${original.body}

PRIOR THREAD (oldest to newest, excluding current message):
${threadMessages.length > 0 ? threadMessages.map(m => `[${m.date}] ${m.from}\n${m.snippet}`).join('\n\n') : '(none; first message in thread)'}

OTHER RECENT EMAIL THREADS WITH THIS SENDER (last 30 days, current thread excluded; snippets only):
${otherThreads || '(none found)'}

RECENT SLACK MENTIONS OF SENDER (last 30 days):
${slackMessages || '(none found)'}

DISMISSED EMAIL PATTERNS (skip if sender or topic matches):
${patterns.length > 0 ? patterns.join('\n') : '(none)'}

TASK:
Decide if this email needs a personalized reply from Sales User.

Skip if: newsletter, automated notification, marketing, calendar invite, FYI/BCC with no expectation of reply, or matches a dismissed pattern.
Draft if: personal request, question, business inquiry, intro reply, scheduling, or any peer-level conversation.

Return ONLY a JSON object, no preamble, no code fences:
{
  "needs_reply": true | false,
  "category": "BD outreach" | "Intro/Networking" | "Internal" | "Scheduling" | "Vendor" | "Press/Podcast" | "Personal" | "Newsletter" | "Notification" | "Other",
  "urgency": "high" | "medium" | "low",
  "confidence": 0.0-1.0,
  "reasoning": "one sentence why",
  "draft": "the full reply body with signature, or empty string if needs_reply is false"
}

If you have low context, draft a short genuine acknowledgment Sales User can flesh out (do not invent specifics).`;

return [{ json: { prompt } }];

const raw = $input.first().json.text || $input.first().json.output || $input.first().json.response || $input.first().json;
const rawStr = typeof raw === 'string' ? raw : JSON.stringify(raw);

let parsed;
try {
  const cleaned = rawStr.replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/```\s*$/, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  parsed = { needs_reply: false, category: 'Other', urgency: 'low', confidence: 0, reasoning: 'JSON parse failed: ' + e.message, draft: '' };
}

const original = $('Filter & Normalize').first().json;
const draftText = (parsed.draft || '').trim();
const draftViable = !!parsed.needs_reply && draftText.length >= 30;

return [{ json: {
  needs_reply: !!parsed.needs_reply,
  draft_viable: draftViable,
  category: parsed.category || 'Other',
  urgency: parsed.urgency || 'low',
  confidence: parsed.confidence ?? 0,
  reasoning: parsed.reasoning || '',
  draft: draftText,
  messageId: original.messageId,
  threadId: original.threadId,
  rfcMessageId: original.rfcMessageId,
  references: original.references,
  from: original.from,
  to: original.to,
  cc: original.cc,
  replyTo: original.replyTo,
  subject: original.subject,
  receivedAt: original.receivedAt,
  raw_llm_output: rawStr.substring(0, 1500)
} }];

const item = $input.first().json;

// Reply-all recipient assembly. Standard email-client behavior:
//   To: original Reply-To (or From) PLUS any other addresses on the original To: line, minus self
//   Cc: original Cc, minus self
// Self addresses are stripped so Sales User never emails himself.

const SELF_PATTERNS = [
  /sales\.user@example\.com/i,
];

function isSelf(addr) {
  return SELF_PATTERNS.some(re => re.test(addr));
}

// Parse a comma-separated address string into address objects.
// Splitter respects commas inside quotes and angle brackets.
function parseAddressList(s) {
  if (!s) return [];
  const out = [];
  let cur = '';
  let inQuote = false, inAngle = 0;
  for (const ch of s) {
    if (ch === '"') inQuote = !inQuote;
    else if (ch === '<') inAngle++;
    else if (ch === '>') inAngle--;
    if (ch === ',' && !inQuote && inAngle === 0) {
      if (cur.trim()) out.push(cur.trim());
      cur = '';
    } else {
      cur += ch;
    }
  }
  if (cur.trim()) out.push(cur.trim());
  return out;
}

function extractEmail(addr) {
  const m = addr.match(/<([^>]+)>/);
  return (m ? m[1] : addr).trim().toLowerCase();
}

// Build To: list. Start from Reply-To (if present) else From. Add original To minus self.
const fromOrReply = (item.replyTo && item.replyTo.trim()) ? item.replyTo : item.from;
const originalTo = parseAddressList(item.to || '');
const originalCc = parseAddressList(item.cc || '');

const toListRaw = [fromOrReply, ...originalTo];
// Dedupe by email and drop self.
const seenTo = new Set();
const toList = [];
for (const addr of toListRaw) {
  if (!addr) continue;
  const email = extractEmail(addr);
  if (!email) continue;
  if (isSelf(addr)) continue;
  if (seenTo.has(email)) continue;
  seenTo.add(email);
  toList.push(addr);
}

const ccList = [];
const seenCc = new Set();
for (const addr of originalCc) {
  const email = extractEmail(addr);
  if (!email) continue;
  if (isSelf(addr)) continue;
  if (seenTo.has(email)) continue; // already in To
  if (seenCc.has(email)) continue;
  seenCc.add(email);
  ccList.push(addr);
}

const subject = item.subject.startsWith('Re:') ? item.subject : `Re: ${item.subject}`;

const headerLines = [];
headerLines.push(`To: ${toList.join(', ')}`);
if (ccList.length > 0) headerLines.push(`Cc: ${ccList.join(', ')}`);
headerLines.push(`Subject: ${subject.replace(/[\r\n]/g, ' ')}`);
if (item.rfcMessageId) {
  headerLines.push(`In-Reply-To: ${item.rfcMessageId}`);
  const refs = item.references ? `${item.references} ${item.rfcMessageId}` : item.rfcMessageId;
  headerLines.push(`References: ${refs}`);
}
headerLines.push('MIME-Version: 1.0');
headerLines.push('Content-Type: text/plain; charset=UTF-8');
headerLines.push('');
headerLines.push(item.draft);

const mime = headerLines.join('\r\n');
const raw = Buffer.from(mime, 'utf-8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

return [{ json: { ...item, raw, threadId: item.threadId, replyToAddresses: toList, replyCcAddresses: ccList } }];

// Verify Pub/Sub push token + decode the message envelope.
// Pub/Sub push payload shape: { message: { data: base64(JSON), messageId, publishTime }, subscription }
const item = $input.first().json;
const body = item.body ?? item;
const query = item.query ?? {};
const headers = item.headers ?? {};
const EXPECTED_TOKEN = $env.PUBSUB_PUSH_TOKEN || 'REPLACE_WITH_PUSH_VERIFICATION_TOKEN';
const presented = query.token || headers['x-pubsub-token'];
if (presented !== EXPECTED_TOKEN) {
  throw new Error('Invalid or missing Pub/Sub token');
}
const msg = body.message || {};
if (!msg.data) {
  // No data is valid (Pub/Sub may probe). Pass an empty signal so downstream can short-circuit.
  return [{ json: { skip: true, reason: 'no message.data' } }];
}
const decoded = JSON.parse(Buffer.from(msg.data, 'base64').toString('utf8'));
return [{ json: {
  emailAddress: decoded.emailAddress,
  historyId: String(decoded.historyId),
  pubsubMessageId: msg.messageId,
  publishTime: msg.publishTime,
  skip: false,
} }];

// Read the persisted lastHistoryId from workflow staticData,
// then advance it to the notification's historyId. We update BEFORE
// fanning out so a slow downstream + redelivered push won't reprocess.
const staticData = $getWorkflowStaticData('global');
const incoming = $input.first().json;
const startHistoryId = staticData.lastHistoryId || incoming.historyId;
staticData.lastHistoryId = incoming.historyId;
return [{ json: {
  startHistoryId: String(startHistoryId),
  currentHistoryId: incoming.historyId,
  emailAddress: incoming.emailAddress,
} }];

// Flatten history records into per-message items, dedupe by messageId,
// and drop anything not actually a new INBOX arrival from someone other than Sales User.
const SELF = ['sales.user@example.com','sales.user@example.com','sales.user@example.com'];
const data = $input.first().json;
const history = data.history || [];
const seen = new Set();
const items = [];
for (const h of history) {
  const adds = h.messagesAdded || [];
  for (const a of adds) {
    const m = a.message || {};
    if (!m.id || seen.has(m.id)) continue;
    // labelIds filter: only INBOX arrivals (history.list already filters but defensive)
    if (!(m.labelIds || []).includes('INBOX')) continue;
    seen.add(m.id);
    items.push({ json: { messageId: m.id, threadId: m.threadId } });
  }
}
if (!items.length) {
  return [{ json: { messageId: null, threadId: null, skip: true, reason: 'no new INBOX messages in history window' } }];
}
return items;

// Seed staticData.lastHistoryId with the baseline returned by users.watch.
// Without this, the very first Pub/Sub notification could miss its message
// because Read+Advance would fall back to incoming.historyId on first run.
const staticData = $getWorkflowStaticData('global');
const resp = $input.first().json;
if (resp.historyId) {
  staticData.lastHistoryId = String(resp.historyId);
}
staticData.lastWatchRenewedAt = new Date().toISOString();
staticData.lastWatchExpiration = resp.expiration ? new Date(Number(resp.expiration)).toISOString() : null;
return [{ json: {
  historyId: resp.historyId,
  expiration: resp.expiration,
  expirationISO: staticData.lastWatchExpiration,
  renewedAt: staticData.lastWatchRenewedAt,
} }];

const messageList = $input.first().json;
const ids = (messageList.messages || []).slice(0, 15).map(m => m.id);

function htmlToText(html) {
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]+/g, ' ')
    .trim();
}

function b64decode(s) {
  return Buffer.from(s.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');
}

function extractBody(payload, preferred) {
  if (!payload) return '';
  if (payload.mimeType?.startsWith(preferred) && payload.body?.data) {
    const decoded = b64decode(payload.body.data);
    return preferred === 'text/html' ? htmlToText(decoded) : decoded;
  }
  if (payload.parts) {
    for (const p of payload.parts) {
      const t = extractBody(p, preferred);
      if (t) return t;
    }
  }
  return '';
}

// Strip quoted reply blocks, forwarded headers, and signatures so we keep only Sales User's prose for voice signal.
function stripQuoted(body) {
  let cut = body.replace(/On\s+[A-Z][a-z]+,?\s+[A-Z][a-z]+\s+\d+,?\s+\d{4}[\s\S]*$/m, '');
  cut = cut.replace(/-{3,}\s*Forwarded message[\s\S]*$/i, '');
  cut = cut.replace(/From:\s+[^\n]+\nSent:[\s\S]*$/i, '');
  cut = cut.replace(/From:\s+[^\n]+\nDate:[\s\S]*$/i, '');
  cut = cut.split('\n').filter(l => !/^\s*>/.test(l)).join('\n');
  return cut.trim();
}

const results = await Promise.all(ids.map(async (id) => {
  try {
    const resp = await this.helpers.httpRequestWithAuthentication.call(
      this,
      'gmailOAuth2',
      {
        method: 'GET',
        url: `https://gmail.googleapis.com/gmail/v1/users/me/messages/${id}`,
        qs: { format: 'full' },
        json: true,
      }
    );
    const headers = (resp.payload?.headers || []).reduce((acc, h) => {
      acc[h.name.toLowerCase()] = h.value;
      return acc;
    }, {});
    const rawBody = extractBody(resp.payload, 'text/plain') || extractBody(resp.payload, 'text/html') || resp.snippet || '';
    const cleanBody = stripQuoted(rawBody);
    if (!cleanBody || cleanBody.length < 30) return null;
    return {
      id,
      subject: headers.subject || '',
      to: headers.to || '',
      date: headers.date || '',
      body: cleanBody.substring(0, 600),
    };
  } catch (e) {
    return null;
  }
}));

const exemplars = results.filter(Boolean);
return [{ json: { exemplars } }];

const calendar = $('Get Calendar Availability').first().json;
const busy = (calendar.calendars?.primary?.busy) || [];

const TZ = 'America/Los_Angeles';
const VIMCAL_LINK = 'https://book.vimcal.com/p/Sales UserSales Userfe41b/Sales UserSales User-30-minute-meeting';
const WORK_START_HOUR = 8;
const WORK_END_HOUR = 18;
const LOOKAHEAD_DAYS = 14;
const MIN_BLOCK_MIN = 60;
const MAX_DAYS = 4;
const STEP_MS = 30 * 60 * 1000;  // half-hour resolution

// Merge overlapping busy ranges first.
const sorted = busy
  .map(b => ({ start: new Date(b.start).getTime(), end: new Date(b.end).getTime() }))
  .filter(b => !Number.isNaN(b.start) && !Number.isNaN(b.end))
  .sort((a, b) => a.start - b.start);

const mergedBusy = [];
for (const r of sorted) {
  const last = mergedBusy[mergedBusy.length - 1];
  if (last && r.start <= last.end) {
    last.end = Math.max(last.end, r.end);
  } else {
    mergedBusy.push({ ...r });
  }
}

function isBusy(ms) {
  for (const b of mergedBusy) {
    if (b.start <= ms && ms < b.end) return true;
  }
  return false;
}

// PT day key + hour using Intl, immune to server TZ.
function ptInfo(ms) {
  const d = new Date(ms);
  const dateStr = d.toLocaleDateString('en-CA', { timeZone: TZ }); // YYYY-MM-DD
  const hour = parseInt(d.toLocaleString('en-US', { timeZone: TZ, hour12: false, hour: '2-digit' }), 10);
  const weekdayName = d.toLocaleDateString('en-US', { timeZone: TZ, weekday: 'short' });
  const weekdays = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  return { dateStr, hour, weekday: weekdays.indexOf(weekdayName) };
}

function fmtTime(ms) {
  return new Date(ms).toLocaleString('en-US', {
    timeZone: TZ,
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  }).toLowerCase().replace(/\s/g, '').replace(':00', '');
}

function fmtDayLabel(dateStr) {
  // dateStr is YYYY-MM-DD in PT. Construct a Date at noon PT to avoid edge cases.
  const d = new Date(`${dateStr}T20:00:00Z`); // 20Z roughly = 12-1pm PT depending on DST
  return d.toLocaleDateString('en-US', {
    timeZone: TZ,
    weekday: 'long',
    month: 'long',
    day: 'numeric',
  });
}

// Walk forward in 30-min steps. Skip the rest of today; start at the next PT midnight.
const now = Date.now();
const startMs = now + 60 * 60 * 1000; // skip the next hour to avoid imminent slots
const endMs = now + LOOKAHEAD_DAYS * 86400000;

const byDay = {}; // dateStr -> list of contiguous free blocks
let currentBlock = null;

for (let t = startMs; t < endMs; t += STEP_MS) {
  const { dateStr, hour, weekday } = ptInfo(t);
  const inWindow = (weekday >= 1 && weekday <= 5) && (hour >= WORK_START_HOUR) && (hour < WORK_END_HOUR);
  const free = inWindow && !isBusy(t) && !isBusy(t + STEP_MS - 1);

  if (free) {
    if (currentBlock && currentBlock.dateStr === dateStr && currentBlock.end === t) {
      currentBlock.end = t + STEP_MS;
    } else {
      if (currentBlock) {
        (byDay[currentBlock.dateStr] = byDay[currentBlock.dateStr] || []).push(currentBlock);
      }
      currentBlock = { dateStr, start: t, end: t + STEP_MS };
    }
  } else if (currentBlock) {
    (byDay[currentBlock.dateStr] = byDay[currentBlock.dateStr] || []).push(currentBlock);
    currentBlock = null;
  }
}
if (currentBlock) {
  (byDay[currentBlock.dateStr] = byDay[currentBlock.dateStr] || []).push(currentBlock);
}

// Filter blocks >= MIN_BLOCK_MIN.
const dayList = [];
for (const [dateStr, blocks] of Object.entries(byDay)) {
  const longBlocks = blocks.filter(b => (b.end - b.start) >= MIN_BLOCK_MIN * 60 * 1000);
  if (longBlocks.length === 0) continue;
  dayList.push({ dateStr, blocks: longBlocks });
}

// Sort chronologically and take top MAX_DAYS.
dayList.sort((a, b) => a.dateStr.localeCompare(b.dateStr));
const top = dayList.slice(0, MAX_DAYS);

// Format for prompt consumption.
const openSlotsFormatted = top.map(d => {
  const label = fmtDayLabel(d.dateStr);
  const ranges = d.blocks.map(b => `${fmtTime(b.start)} - ${fmtTime(b.end)} PT`).join(', ');
  return `${label}: ${ranges}`;
}).join('\n');

return [{ json: {
  openSlots: top,
  openSlotsFormatted: openSlotsFormatted || '(no open blocks of 60+ min in working hours over next 14 days)',
  vimcalLink: VIMCAL_LINK,
} }];
